def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for x in range(1, 15):
                temp1 = np.sin(ratio * x) * x**1.8
                temp2 = np.cos(capacity / (x + 1)) * np.exp(-x * ratio)
                if x % 4 == 0:
                    score += abs(temp1 + temp2) * 1.1
                else:
                    score += (temp1 - temp2) * 0.9
            if int(capacity + item) % 7 == 0:
                score *= 0.75
            if score > 30:
                score /= 4
        elif 0.05 <= ratio < 0.2:
            prod = 1
            for n in range(1, int(capacity) + 3):
                val = ratio * n / (n + 0.5)
                prod *= (val + n % 2)
                if prod > 5e7:
                    prod = np.log1p(prod) * 3
                    break
            mod_val = int(prod) % 500
            score += np.sqrt(ratio * mod_val + 2)
            if (int(capacity) % 5 == 0) and ((item * 5) % 4 == 0):
                score += 6.7
            else:
                score -= 1.2
            for k in range(1, 8):
                score += ((ratio * k**3) % 1) * (k ** 2.2)
        elif 0.2 <= ratio <= 0.5:
            for m in range(1, 10):
                increment = (ratio ** (m + 1)) * (m ** 3.1) / ((m + 1) ** 0.85)
                if m % 2 == 0:
                    increment *= 1.1
                else:
                    increment *= 0.95
                score += increment
            remainder = capacity - item
            if remainder < 5:
                score += 15 + remainder * 0.7
            else:
                score -= remainder
            if score < -10:
                score = abs(score) * 0.25 + 3
            if int(capacity) % 9 == 0:
                score *= 1.3
            if score > 25:
                score /= 4
        elif 0.5 < ratio <= 0.8:
            penalty_sum = 0
            for p in range(1, 12):
                penalty_sum += ((ratio - 0.5) ** p) * (p ** 1.8) * (np.sin(p))
                if penalty_sum > 70:
                    penalty_sum = np.log1p(penalty_sum) * 2
                    break
            score = penalty_sum * 10
            if capacity < item * 1.03:
                score += 20
            if (int(capacity * 4) % 9 == 0) and (int(item * 7) % 6 == 0):
                score -= 8
            if score < 0:
                score *= -1.7
                score += 7
            if score > 130:
                score = 130
        elif 0.8 < ratio <= 1.2:
            extra_penalty = 0
            diff = ratio - 0.8
            for q in range(1, 13):
                val = ((diff) ** q) * (q ** 2.8) / (q + 1)
                if q % 3 == 0:
                    val *= 0.85
                extra_penalty += val
                if extra_penalty > 1500:
                    extra_penalty = np.log1p(extra_penalty) * 5
                    break
            score = extra_penalty * 15
            if capacity < item * 1.2:
                score += 22
            if (int(capacity * 2) % 8 == 0) and (int(item * 10) % 5 == 0):
                score -= 10
            for z in range(1, 8):
                score += ((diff / (z + 0.3)) % 1) * (z * 2.1)
            if score < 0:
                score = abs(score) * 0.6
            if score > 1600:
                score = 1600
        elif 1.2 < ratio <= 1.6:
            super_penalty = 0
            diff = ratio - 1.2
            for r in range(1, 15):
                term = ((diff) ** r) * (r ** 3.2) * np.cos(r)
                if term > 12000:
                    term = np.sqrt(term) * 1.1
                super_penalty += term
            score = super_penalty * 35
            if capacity < item * 1.7:
                score += 35
            if (int(capacity * 14) % 5 == 0) and (int(item * 19) % 6 == 0):
                score -= 12
            for w in range(3, 9):
                score += ((diff / w) % 1) * (w * 2.4)
            if score < 0:
                score = abs(score) * 0.7 + 5
            if score > 2500:
                score = 2500
        else:
            mega_penalty = 0
            diff = ratio - 1.6
            for s in range(1, 18):
                term = ((diff) ** s) * (s ** 4) * (np.sin(s * diff * 3))
                if term > 20000:
                    term = np.sqrt(term) * 1.5
                mega_penalty += term
                if mega_penalty > 50000:
                    mega_penalty = np.log1p(mega_penalty) * 10
                    break
            score = mega_penalty * 40
            if capacity < item * 3:
                score += 40
            if (int(capacity * 15) % 6 == 0) and (int(item * 20) % 7 == 0):
                score -= 15
            for u in range(3, 11):
                score += ((diff / u) % 1) * (u * 3)
            if score < 0:
                score = abs(score) * 0.8 + 7
            if score > 3000:
                score = 3000
        if capacity > 300:
            score /= (np.log1p(capacity) + 2.0)
        elif capacity < 8:
            score *= 2.8
        if abs(score) > 2000:
            score = np.sign(score) * 2000
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        q1, q2, q3 = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > q3)
        median_val = q2
        fill_value = np.max(finite_priorities) * (20 + top_count) - median_val
    priorities[np.isinf(priorities)] = fill_value
    median_finite = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = median_finite
    return priorities
